namespace EnterpriseSso.Web
{
    using EnterpriseSso.Saml;
    using Microsoft.AspNetCore.Builder;
    using Microsoft.AspNetCore.Http;
    using Microsoft.Extensions.DependencyInjection;
    using Microsoft.Extensions.Hosting;

    public sealed class SamlSigningOptions
    {
        public string PfxPath { get; set; } = "";
        public string PfxPassword { get; set; } = "";
        public string Issuer { get; set; } = "";
        public string Destination { get; set; } = "";
        public string AssertionConsumerServiceUrl { get; set; } = "";
    }

    public static class Program
    {
        public static void Main(string[] args)
        {
            var builder = WebApplication.CreateBuilder(args);
            builder.Services.AddRouting();
            builder.Services.AddSingleton(sp =>
            {
                var cfg = builder.Configuration;
                return new SamlSigningOptions
                {
                    PfxPath = cfg["Saml:PfxPath"] ?? "",
                    PfxPassword = cfg["Saml:PfxPassword"] ?? "",
                    Issuer = cfg["Saml:Issuer"] ?? "",
                    Destination = cfg["Saml:Destination"] ?? "",
                    AssertionConsumerServiceUrl = cfg["Saml:AssertionConsumerServiceUrl"] ?? ""
                };
            });

            var app = builder.Build();

            app.MapGet("/saml/authnrequest", async (HttpContext ctx, SamlSigningOptions cfg) =>
            {
                var cert = LoadCertificate(cfg.PfxPath, cfg.PfxPassword);

                var options = new SamlAuthnRequestOptions
                {
                    Issuer = cfg.Issuer,
                    Destination = cfg.Destination,
                    AssertionConsumerServiceUrl = cfg.AssertionConsumerServiceUrl,
                    RelayState = ctx.Request.Query["RelayState"].FirstOrDefault(),
                    ForceAuthn = string.Equals(ctx.Request.Query["ForceAuthn"], "true", StringComparison.OrdinalIgnoreCase),
                    IsPassive = string.Equals(ctx.Request.Query["IsPassive"], "true", StringComparison.OrdinalIgnoreCase)
                };

                var result = SamlAuthnRequestBuilder.BuildAndSign(options, cert);

                ctx.Response.ContentType = "application/json; charset=utf-8";
                await ctx.Response.WriteAsync(System.Text.Json.JsonSerializer.Serialize(new
                {
                    result.RequestId,
                    result.RequestXml,
                    result.RequestXmlSigned,
                    result.SamlRequestBase64,
                    result.SamlRequestBase64Deflated,
                    result.RelayState
                }));
            });

            app.MapPost("/crypto/des/encrypt", async (HttpContext ctx) =>
            {
                var form = await ctx.Request.ReadFormAsync();
                var plaintext = form["plaintext"].ToString();
                var keyB64 = form["key"].ToString();
                var ivB64 = form["iv"].ToString();

                var res = LegacySymmetricEncryption.EncryptDesCbcPkcs7(
                    plaintext,
                    Convert.FromBase64String(keyB64),
                    Convert.FromBase64String(ivB64));

                ctx.Response.ContentType = "application/json; charset=utf-8";
                await ctx.Response.WriteAsync(System.Text.Json.JsonSerializer.Serialize(res));
            });

            app.MapPost("/crypto/3des/encrypt", async (HttpContext ctx) =>
            {
                var form = await ctx.Request.ReadFormAsync();
                var plaintext = form["plaintext"].ToString();
                var keyB64 = form["key"].ToString();
                var ivB64 = form["iv"].ToString();

                var res = LegacySymmetricEncryption.EncryptTripleDesCbcPkcs7(
                    plaintext,
                    Convert.FromBase64String(keyB64),
                    Convert.FromBase64String(ivB64));

                ctx.Response.ContentType = "application/json; charset=utf-8";
                await ctx.Response.WriteAsync(System.Text.Json.JsonSerializer.Serialize(res));
            });

            app.Run();
        }

        private static X509Certificate2 LoadCertificate(string pfxPath, string password)
        {
            if (string.IsNullOrWhiteSpace(pfxPath)) throw new InvalidOperationException("Saml:PfxPath not configured.");
            if (!File.Exists(pfxPath)) throw new FileNotFoundException("PFX not found.", pfxPath);

            return new X509Certificate2(
                pfxPath,
                password ?? "",
                X509KeyStorageFlags.MachineKeySet | X509KeyStorageFlags.EphemeralKeySet | X509KeyStorageFlags.Exportable);
        }
    }
